#!/usr/bin/env node
/**
 * Vendors foliate-js into the app so the ebook reader works OFFLINE (no
 * jsdelivr CDN at read time). Bundles foliate-js/view.js and its whole module
 * tree (static + dynamic imports: epub, mobi, fb2, comic-book, zip, fflate,
 * paginator, fixed-layout, search, tts, …) into ONE self-contained ESM string,
 * emitted as native/utils/foliateBundle.ts.
 *
 * Regenerate (e.g. to bump the foliate-js version):
 *   npm run build:foliate
 *
 * The bundle is inlined into the reader's WebView HTML (see ReaderScreen's
 * ebookHtml) as an inline module script — inline modules don't hit the
 * file:// CORS wall that blocks external `import`/`<script src>` in Android
 * WebView, which is why the CDN was used before.
 */
import { build } from "esbuild";
import { writeFileSync, mkdirSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { createRequire } from "node:module";

const require = createRequire(import.meta.url);
const here = dirname(fileURLToPath(import.meta.url));
const nativeRoot = resolve(here, "..");

const FOLIATE_VERSION = require(
  resolve(nativeRoot, "node_modules/foliate-js/package.json")
).version;

const entry = resolve(nativeRoot, "node_modules/foliate-js/view.js");

const result = await build({
  entryPoints: [entry],
  bundle: true,
  format: "esm",
  minify: true,
  write: false,
  legalComments: "none",
  // Emulator/phone WebView is modern Chromium — target current Chrome so
  // esbuild doesn't down-level features foliate relies on.
  target: ["chrome100"],
});

const code = result.outputFiles[0].text;

// Guard: fail loudly if any external network reference survived the bundle —
// the whole point is zero read-time network.
const external = code.match(/https?:\/\/cdn\.jsdelivr\.net|https?:\/\/unpkg\.com|https?:\/\/esm\.sh/g);
if (external) {
  throw new Error(`Bundle still references a CDN: ${[...new Set(external)].join(", ")}`);
}
// `</script` in the payload would break the inline <script> host; esbuild
// never emits it, but assert so a future foliate version can't silently break.
if (code.includes("</script")) {
  throw new Error("Bundle contains </script — would break the inline host HTML");
}

const out = `// AUTO-GENERATED by scripts/build-foliate-bundle.mjs — DO NOT EDIT.
// Vendored foliate-js@${FOLIATE_VERSION}, bundled to one self-contained ESM
// module so the ebook reader renders offline (no jsdelivr CDN). Regenerate:
//   npm run build:foliate
/* eslint-disable */
export const FOLIATE_VERSION = ${JSON.stringify(FOLIATE_VERSION)};
export const FOLIATE_BUNDLE = ${JSON.stringify(code)};
`;

const outPath = resolve(nativeRoot, "utils/foliateBundle.ts");
mkdirSync(dirname(outPath), { recursive: true });
writeFileSync(outPath, out);

console.log(
  `Wrote utils/foliateBundle.ts — foliate-js@${FOLIATE_VERSION}, ${(code.length / 1024).toFixed(1)} KB bundle`
);
